// ═══════════════════════════════════════════════════════════════════
// Global landing dashboard — account view recapping BOTH exams,
// countdowns + adaptive daily plan (recomputed every visit)
// ═══════════════════════════════════════════════════════════════════
let currentView = 'landing';
function examDates(){
 const d = JSON.parse(localStorage.getItem('esther_examdates')||'null') || {e1:'2026-07-02',e2:'2026-06-18'};
 // one-time migration: the MAC/OmI exam moved from 28 June to 2 July. Self-heals even if an
 // old value comes back from the cloud on sync (re-applied on every read, then pushed back).
 if(d.e1==='2026-06-28'){ d.e1='2026-07-02'; localStorage.setItem('esther_examdates',JSON.stringify(d)); if(typeof schedulePush==='function') schedulePush(); }
 return d;
}
function setExamDate(which){
 const d=examDates(); const cur=d[which];
 const msg=lang==='fr'?'Date de l\'examen (AAAA-MM-JJ):':lang==='en'?'Exam date (YYYY-MM-DD):':'Examendatum (JJJJ-MM-DD):';
 const v=prompt(msg, cur); if(!v) return;
 if(!/^\d{4}-\d{2}-\d{2}$/.test(v.trim())){ return; }
 d[which]=v.trim(); localStorage.setItem('esther_examdates',JSON.stringify(d)); if(typeof schedulePush==='function') schedulePush(); buildLanding();
}
function daysLeftTo(dateStr){
 const now=new Date(); const t=new Date(now.getFullYear(),now.getMonth(),now.getDate());
 const p=dateStr.split('-').map(Number); const ex=new Date(p[0],p[1]-1,p[2]);
 return Math.round((ex-t)/86400000);
}
function fmtDate(dateStr){
 const p=dateStr.split('-').map(Number); const d=new Date(p[0],p[1]-1,p[2]);
 const loc=lang==='fr'?'fr-FR':lang==='en'?'en-GB':'nl-NL';
 return d.toLocaleDateString(loc,{day:'numeric',month:'long'});
}
function examStats(which){
 const dates=examDates();
 let total=0, mastered=0, scope;
 if(which==='e2'){ PM_UNITS.forEach(u=>{ total+=u.exercises.length; mastered+=u.exercises.filter(e=>pmCorrectSet.has(e.id)).length; }); scope=a=>/^u\d+_/.test(a.id); }
 else { const m=masteryData(); total=m.mac.reduce((s,x)=>s+x.n,0)+m.omi.reduce((s,x)=>s+x.n,0); mastered=m.mac.reduce((s,x)=>s+x.ok,0)+m.omi.reduce((s,x)=>s+x.ok,0); scope=a=>(a.id.startsWith('ex')||a.id.startsWith('h'))&&!a.id.startsWith('lvl_'); }
 const remaining=Math.max(0,total-mastered);
 const daysLeft=daysLeftTo(dates[which]);
 const perDay= remaining>0 ? Math.ceil(remaining/Math.max(1,daysLeft)): 0;
 const today=dayKey(Date.now());
 const doneToday=attempts.filter(a=>scope(a)&&a.ok&&dayKey(a.ts)===today).length;
 return {total,mastered,remaining,daysLeft,perDay,doneToday,pct:total?Math.round(mastered/total*100):0,date:dates[which]};
}
function landingLabels(){
 if(lang==='fr') return {hi:'Salut Esther 👋',sub:'Ton tableau de bord — tes deux examens en un coup d\'œil.',mastered:'maîtrisés',enter:'Ouvrir',plan:'🗓️ Ton plan du jour',planSub:'Recalculé à chaque visite selon ton retard et les jours restants.',today:'aujourd\'hui',perDay:'exos/jour',done:'🎉 Tout est maîtrisé — révise et fais les examens blancs !',examDay:'📣 C\'est bientôt — fonce sur les révisions !',passed:'Examen passé',edit:'modifier',goalMet:'objectif du jour atteint ✅',behindMsg:d=>`Plus que ${d} jours — accélère un peu 💪`,onTrackMsg:'Tu es dans les temps 👍'};
 if(lang==='en') return {hi:'Hi Esther 👋',sub:'Your dashboard — both exams at a glance.',mastered:'mastered',enter:'Open',plan:'🗓️ Your plan for today',planSub:'Recomputed every visit from your backlog and days left.',today:'today',perDay:'ex/day',done:'🎉 All mastered — revise & do mock exams!',examDay:'📣 Almost there — focus on revision!',passed:'Exam over',edit:'edit',goalMet:'daily goal reached ✅',behindMsg:d=>`Only ${d} days left — pick up the pace 💪`,onTrackMsg:'You\'re on track 👍'};
 return {hi:'Hoi Esther 👋',sub:'Je dashboard — beide examens in één oogopslag.',mastered:'beheerst',enter:'Openen',plan:'🗓️ Je plan voor vandaag',planSub:'Elke keer herberekend op basis van je achterstand en resterende dagen.',today:'vandaag',perDay:'oef/dag',done:'🎉 Alles beheerst — herhaal & doe proefexamens!',examDay:'📣 Bijna zover — focus op herhalen!',passed:'Examen voorbij',edit:'wijzigen',goalMet:'dagdoel gehaald ✅',behindMsg:d=>`Nog ${d} dagen — tempo omhoog 💪`,onTrackMsg:'Je ligt op schema 👍'};
}
function examCardHtml(which){
 const LL=landingLabels(); const s=examStats(which);
 const cls=which==='e2'?'e2':'e1';
 const name=which==='e2'?'📋 Process Management':'🧮 MAC & 📘 OmI';
 const enterN=which==='e2'?2:1;
 const cd = s.daysLeft<0 ? '✓': 'J-'+s.daysLeft;
 let plan;
 if(s.remaining===0) plan=`<div class="ed-plan">${LL.done}</div>`;
 else if(s.daysLeft<=0) plan=`<div class="ed-plan">${LL.examDay}</div>`;
 else { const met=s.doneToday>=s.perDay; plan=`<div class="ed-plan">${LL.today.charAt(0).toUpperCase()+LL.today.slice(1)}: <b>${s.doneToday}/${s.perDay}</b> ${LL.perDay} ${met?'· '+LL.goalMet:''}</div>`; }
 return `<div class="exam-dash ${cls}" onclick="enterExam(${enterN})">
 <div class="ed-top"><div><div class="ed-name">${name}</div><div class="ed-sub">${fmtDate(s.date)}</div></div>
 <div class="ed-cd"><div class="d">${cd}</div><div class="l">${s.daysLeft<0?LL.passed:fmtDate(s.date)}</div></div></div>
 <div class="ed-bar"><i style="width:${s.pct}%"></i></div>
 <div class="ed-stats"><span>${s.mastered}/${s.total} ${LL.mastered}</span><span>${s.pct}%</span></div>
 ${plan}
 <div class="ed-go">${LL.enter} →</div></div>`;
}
function buildLanding(){
 const area=document.getElementById('landingArea'); const LL=landingLabels(); const li=levelInfo(XP);
 const e2=examStats('e2'), e1=examStats('e1');
 const today=dayKey(Date.now()); const todayTotal=attempts.filter(a=>dayKey(a.ts)===today).length;
 // plan rows ordered by urgency (fewer days first)
 const rows=[{w:'e2',s:e2,c:'#0d9488',n:'Process Management'},{w:'e1',s:e1,c:'#D4537E',n:'MAC & OmI'}].sort((a,b)=>a.s.daysLeft-b.s.daysLeft);
 const planRows=rows.map(r=>{
 let txt;
 if(r.s.remaining===0) txt=`<b>${r.n}</b> — ${LL.done}`;
 else if(r.s.daysLeft<=0) txt=`<b>${r.n}</b> — ${LL.examDay}`;
 else txt=`<b>${r.n}</b> — ${r.s.perDay} ${LL.perDay} · ${r.s.daysLeft<=4?LL.behindMsg(r.s.daysLeft):LL.onTrackMsg}`;
 const prog=r.s.remaining===0?'✓':`${r.s.doneToday}/${r.s.perDay}`;
 return `<div class="plan-row"><span class="pr-dot" style="background:${r.c}"></span><span class="pr-txt">${txt}</span><span class="pr-prog" style="color:${r.c}">${prog}</span></div>`;
 }).join('');
 const loginBanner = syncCode ? '': (()=>{ const L=homeLabels(); return `<div class="login-banner">
 <div class="login-banner-txt"><div class="lt">${L.loginTitle}</div><div class="ls">${L.loginSub}</div></div>
 <div class="login-banner-row"><input id="loginCodeInput" class="login-input" type="text" value="iloveesther" placeholder="${L.loginPlaceholder}" onkeydown="if(event.key==='Enter')submitSyncCode()"><button class="login-go" onclick="submitSyncCode()">${L.loginBtn}</button></div></div>`; })();
 area.innerHTML = `
${loginBanner}
<div class="land-hero"><h1>${LL.hi}</h1><p>${LL.sub}</p></div>
<div class="stat-grid" style="margin-top:18px">
 <div class="stat-card"><div class="big">🔥 ${calcStreak()}</div><div class="lbl">${homeLabels().streak}</div></div>
 <div class="stat-card"><div class="big"><span style="background:#f59e0b;color:#fff;border-radius:10px;padding:1px 9px;font-size:1.2rem;font-weight:700">${li.level}</span></div><div class="lbl">${li.title} · ${XP} XP</div></div>
 <div class="stat-card"><div class="big">✅ ${todayTotal}</div><div class="lbl">${homeLabels().today}</div></div>
 <div class="stat-card"><div class="big">🏅 ${badges.size}/${BADGES.length}</div><div class="lbl">badges</div></div></div>
<div class="exam-cards">${examCardHtml('e2')}${examCardHtml('e1')}</div>
<div class="plan-banner"><h3>${LL.plan}</h3><div class="sub" style="font-size:0.8rem;color:var(--muted);margin-bottom:8px">${LL.planSub}</div>${planRows}</div>
<div style="text-align:center;font-size:0.78rem;color:var(--muted)">📅 ${LL.edit}: <span class="date-edit" onclick="setExamDate('e2')">Process Mgmt ${fmtDate(e2.date)}</span> · <span class="date-edit" onclick="setExamDate('e1')">MAC/OmI ${fmtDate(e1.date)}</span></div>`;
}
function showLanding(){
 currentView='landing';
 ['homeWrap','macWrap','omiWrap','testWrap','lvlWrap','theoryWrap','exam2Wrap'].forEach(id=>{const el=document.getElementById(id);if(el)el.style.display='none';});
 ['examSwitcher','subjSwitcher','pmTabsContainer','globalProgress'].forEach(id=>{const el=document.getElementById(id);if(el)el.style.display='none';});
 const cs=document.getElementById('btnCS'); if(cs) cs.style.display='none';
 document.getElementById('landingWrap').style.display='';
 buildLanding();
}
function enterExam(n){
 currentView='exam';
 document.getElementById('landingWrap').style.display='none';
 ['examSwitcher','subjSwitcher'].forEach(id=>{const el=document.getElementById(id);if(el)el.style.display='';});
 switchExam(n);
}

function buildHome(){
 const L = homeLabels();
 const area = document.getElementById('homeArea');
 const pm = currentExam===2;
 const inScope = a => /^u\d+_/.test(a.id)===pm && !a.id.startsWith('lvl_') && (pm || a.id.startsWith('ex')||a.id.startsWith('h'));
 const sAtt = attempts.filter(inScope);
 const today = dayKey(Date.now());
 const todayAtt = sAtt.filter(a=>dayKey(a.ts)===today);
 const week = sAtt.filter(a=>a.ts > Date.now()-7*86400000);
 const acc = week.length ? Math.round(week.filter(a=>a.ok).length/week.length*100): null;
 const weak = weakSpots(pm?'pm':'mac');

 const bar = (x, color) => {
 const pct = x.n ? Math.round(x.ok/x.n*100): 0;
 return `<div class="mast-row" onclick="goToMastery('${x.key}',${x.idx})"><span class="nm">${x.label}</span><div class="bar"><div class="fill" style="width:${pct}%;background:${color}"></div></div><span class="pct" style="color:${color}">${pct}%</span></div>`;
 };

 // exam-scoped mastery + totals + nav + hero
 let mastBlocks, totN, totOk, navCards, hero;
 if(pm){
 const pmM = pmMasteryData();
 totN = pmM.reduce((s,x)=>s+x.n,0); totOk = pmM.reduce((s,x)=>s+x.ok,0);
 mastBlocks = `<div class="mastery-section"><h3>📋 ${L.pmMastery}</h3>${pmM.map(x=>bar(x,PM_AC)).join('')}</div>`;
 navCards = `
 <div class="nav-card" onclick="switchSubject('pm')"><div class="ic">📋</div><div class="ti">${L.navPm.ti}</div><div class="su">${L.navPm.su}</div></div>
 <div class="nav-card" onclick="switchSubject('test')"><div class="ic">🎓</div><div class="ti">${L.navTest.ti}</div><div class="su">${L.navTest.su}</div></div>
 <div class="nav-card" onclick="switchSubject('lvl')"><div class="ic">📶</div><div class="ti">${L.navLvl.ti}</div><div class="su">${L.navLvl.su}</div></div>
 <div class="nav-card" onclick="switchSubject('theory')"><div class="ic">📖</div><div class="ti">${L.navTheory.ti}</div><div class="su">${L.navTheory.su}</div></div>
 <div class="nav-card" onclick="openFlash()"><div class="ic">🃏</div><div class="ti">${L.navFlash.ti}</div><div class="su">${L.navFlash.su}</div></div>`;
 hero = `<div class="home-hero"><h1>${L.hiPm}</h1><p>${L.subPm}</p></div>`;
 } else {
 const m = masteryData();
 totN = m.mac.reduce((s,x)=>s+x.n,0)+m.omi.reduce((s,x)=>s+x.n,0);
 totOk = m.mac.reduce((s,x)=>s+x.ok,0)+m.omi.reduce((s,x)=>s+x.ok,0);
 mastBlocks = `<div class="mastery-section"><h3>🧮 ${L.mac}</h3>${m.mac.map(x=>bar(x,'var(--primary)')).join('')}</div>
<div class="mastery-section"><h3>📘 ${L.omi}</h3>${m.omi.map(x=>bar(x,'#f97316')).join('')}</div>`;
 navCards = `
 <div class="nav-card" onclick="switchSubject('mac')"><div class="ic">🧮</div><div class="ti">${L.navMac.ti}</div><div class="su">${L.navMac.su}</div></div>
 <div class="nav-card" onclick="switchSubject('omi')"><div class="ic">📘</div><div class="ti">${L.navOmi.ti}</div><div class="su">${L.navOmi.su}</div></div>
 <div class="nav-card" onclick="switchSubject('test')"><div class="ic">🎓</div><div class="ti">${L.navTest.ti}</div><div class="su">${L.navTest.su}</div></div>
 <div class="nav-card" onclick="switchSubject('lvl')"><div class="ic">📶</div><div class="ti">${L.navLvl.ti}</div><div class="su">${L.navLvl.su}</div></div>
 <div class="nav-card" onclick="switchSubject('theory')"><div class="ic">📖</div><div class="ti">${L.navTheory.ti}</div><div class="su">${L.navTheory.su}</div></div>
 <div class="nav-card" onclick="openFlash()"><div class="ic">🃏</div><div class="ti">${L.navFlash.ti}</div><div class="su">${L.navFlash.su}</div></div>`;
 hero = `<div class="home-hero"><h1>${L.hi}</h1><p>${L.sub}</p></div>`;
 }

 const loginBanner = syncCode ? '': `
<div class="login-banner">
 <div class="login-banner-txt"><div class="lt">${L.loginTitle}</div><div class="ls">${L.loginSub}</div></div>
 <div class="login-banner-row">
 <input id="loginCodeInput" class="login-input" type="text" value="iloveesther" placeholder="${L.loginPlaceholder}" onkeydown="if(event.key==='Enter')submitSyncCode()">
 <button class="login-go" onclick="submitSyncCode()">${L.loginBtn}</button></div></div>`;

 area.innerHTML = `
${loginBanner}
${hero}
<div class="stat-grid">
 <div class="stat-card"><div class="big">🔥 ${calcStreakFrom(sAtt)}</div><div class="lbl">${L.streak}</div></div>
 ${dailyRingHtml(todayAtt.length)}
 <div class="stat-card"><div class="big">🎯 ${acc===null?'—':acc+'%'}</div><div class="lbl">${L.acc}</div></div>
 <div class="stat-card"><div class="big">📈 ${totN?Math.round(totOk/totN*100):0}%</div><div class="lbl">${L.prog}</div></div></div>
${xpCardHtml()}
<div class="nav-grid">${navCards}</div>
${reviewCardHtml()}
${mastBlocks}
${coverageHtml()}
${badgesHtml()}`;
 // global progress bar reflects current exam home
 const gp=document.getElementById('globalProgress'); if(gp) gp.style.display='none';
}

function submitSyncCode(){
 const inp = document.getElementById('loginCodeInput');
 if(!inp) return;
 const code = inp.value.trim();
 if(!code) return;
 syncCode = code;
 localStorage.setItem('esther_sync_code', syncCode);
 updateSyncBtn();
 syncPull().then(()=>{ syncPush(); buildHome(); });
}

function goToMastery(key, idx){
 if(key==='pm'){ switchSubject('pm'); switchPmTab(idx); }
 else if(key.startsWith('w')){ switchSubject('mac'); switchTab(idx); }
 else { switchSubject('omi'); switchOmiTab(idx); }
}

// ── Dark mode ──
function toggleDark(){
 const on = document.documentElement.classList.toggle('dark');
 localStorage.setItem('esther_dark', on?'1':'0');
 const btn = document.getElementById('darkBtn');
 if(btn) btn.textContent = on?'☀️':'🌙';
}
if(localStorage.getItem('esther_dark')==='1'){ document.documentElement.classList.add('dark'); }

