const FLASHCARDS = [{"cat":"mac","front_nl":"Formule: lineaire afschrijving ?","front_en":"Formula: straight-line depreciation?","front_fr":"Formule: amortissement linéaire ?","back_nl":"<strong>d = (A − R) / n</strong>. A = aanschafprijs, R = restwaarde, n = levensduur in jaren; elk jaar boek je hetzelfde bedrag.","back_en":"<strong>d = (A − R) / n</strong>. A = purchase price, R = residual value, n = useful life in years; the same charge is recorded every year.","back_fr":"<strong>d = (A − R) / n</strong>. A = prix d'acquisition, R = valeur résiduelle, n = durée de vie; on comptabilise le même montant chaque année."},{"cat":"mac","front_nl":"Formule: boekwaarde na t jaar (lineair) ?","front_en":"Formula: book value after t years (linear)?","front_fr":"Formule: valeur comptable après t ans (linéaire) ?","back_nl":"<strong>BW_t = A − t × d</strong>. Trek t keer de jaarlijkse afschrijving d af van de aanschafprijs A.","back_en":"<strong>BW_t = A − t × d</strong>. Subtract t years of annual depreciation d from the purchase price A.","back_fr":"<strong>BW_t = A − t × d</strong>. Soustrayez t fois l'amortissement annuel d du prix d'acquisition A."},{"cat":"mac","front_nl":"Formule: afschrijvingspercentage bij vast % van de boekwaarde ?","front_en":"Formula: rate for the declining balance method?","front_fr":"Formule: taux de la méthode dégressive à taux fixe ?","back_nl":"<strong>p = 1 − (R/A)^(1/n)</strong>. Dit vaste percentage pas je elk jaar toe op de <strong>resterende boekwaarde</strong>, niet op A; BW daalt nooit onder R.","back_en":"<strong>p = 1 − (R/A)^(1/n)</strong>. Apply this fixed rate each year to the <strong>remaining book value</strong>, not to A; BW never falls below R.","back_fr":"<strong>p = 1 − (R/A)^(1/n)</strong>. Ce taux fixe s'applique chaque année à la <strong>valeur comptable restante</strong>, pas à A; la VC ne descend jamais sous R."},{"cat":"mac","front_nl":"Formule: boekwaarde bij vast % boekwaarde ?","front_en":"Formula: book value under declining balance?","front_fr":"Formule: valeur comptable en méthode dégressive ?","back_nl":"<strong>BW_t = BW_{t−1} × (1 − p)</strong>. De boekwaarde krimpt elk jaar met factor (1−p), dus de afschrijving wordt elk jaar kleiner.","back_en":"<strong>BW_t = BW_{t−1} × (1 − p)</strong>. Book value shrinks by factor (1−p) each year, so depreciation also shrinks.","back_fr":"<strong>BW_t = BW_{t−1} × (1 − p)</strong>. La valeur comptable diminue chaque année du facteur (1−p), donc l'amortissement diminue aussi."},{"cat":"mac","front_nl":"Formule: cijfersommethode (SYD) ?","front_en":"Formula: sum-of-years-digits method?","front_fr":"Formule: méthode de la somme des chiffres (SYD) ?","back_nl":"<strong>S = n(n+1)/2</strong> en <strong>d_t = ((n − t + 1)/S) × (A − R)</strong>. Jaar 1 krijgt het hoogste gewicht (n/S), het laatste jaar het laagste (1/S).","back_en":"<strong>S = n(n+1)/2</strong> and <strong>d_t = ((n − t + 1)/S) × (A − R)</strong>. Year 1 gets the highest weight (n/S), the last year the lowest (1/S).","back_fr":"<strong>S = n(n+1)/2</strong> et <strong>d_t = ((n − t + 1)/S) × (A − R)</strong>. L'année 1 reçoit le poids le plus élevé (n/S), la dernière le plus faible (1/S)."},{"cat":"mac","front_nl":"Formule: dalend vast bedrag (afschrijving) ?","front_en":"Formula: decreasing fixed amount depreciation?","front_fr":"Formule: amortissement à montant dégressif fixe ?","back_nl":"<strong>n × d₁ − Δ × n(n−1)/2 = A − R</strong>. d₁ = afschrijving jaar 1, Δ = vaste jaarlijkse daling; los op voor de onbekende.","back_en":"<strong>n × d₁ − Δ × n(n−1)/2 = A − R</strong>. d₁ = year-1 depreciation, Δ = fixed annual decrease; solve for the unknown.","back_fr":"<strong>n × d₁ − Δ × n(n−1)/2 = A − R</strong>. d₁ = dotation de l'année 1, Δ = diminution annuelle fixe; résolvez pour l'inconnue."},{"cat":"mac","front_nl":"Definitie: boekwaarde ?","front_en":"Definition: book value?","front_fr":"Définition: valeur comptable ?","back_nl":"De waarde van een actief dat <strong>nog op de balans staat</strong> na t jaar: aanschafprijs min gecumuleerde afschrijvingen.","back_en":"The value of an asset <strong>still on the balance sheet</strong> after t years: purchase price minus accumulated depreciation.","back_fr":"La valeur d'un actif <strong>encore au bilan</strong> après t ans: prix d'acquisition moins amortissements cumulés."},{"cat":"mac","front_nl":"Formule: integrale kostprijs k ?","front_en":"Formula: full (absorption) cost price k?","front_fr":"Formule: coût de revient complet k ?","back_nl":"<strong>k = C/N + v</strong>. C = vaste kosten, N = normale bezetting, v = variabele kost per eenheid; C/N is het aandeel vaste kosten dat elke eenheid draagt.","back_en":"<strong>k = C/N + v</strong>. C = fixed costs, N = normal capacity, v = variable cost per unit; C/N is each unit's share of fixed costs.","back_fr":"<strong>k = C/N + v</strong>. C = coûts fixes, N = capacité normale, v = coût variable unitaire; C/N est la part des coûts fixes portée par chaque unité."},{"cat":"mac","front_nl":"Formule: verkoopresultaat (VR) ?","front_en":"Formula: sales result (VR)?","front_fr":"Formule: résultat sur ventes (VR) ?","back_nl":"<strong>VR = (p − k) × afzet</strong>. Winst per verkochte eenheid maal het aantal <strong>verkochte</strong> eenheden — gebruik afzet, niet productie W!","back_en":"<strong>VR = (p − k) × sales volume</strong>. Profit per unit sold times the number of units <strong>sold</strong> — use sales, not production W!","back_fr":"<strong>VR = (p − k) × ventes</strong>. Profit par unité vendue multiplié par le nombre d'unités <strong>vendues</strong> — utilisez les ventes, pas la production W !"},{"cat":"mac","front_nl":"Formule + definitie: bezettingsresultaat (BezR) ?","front_en":"Formula + definition: capacity (occupancy) result?","front_fr":"Formule + définition: résultat d'occupation (BezR) ?","back_nl":"<strong>BezR = (W − N) × (C/N)</strong>. Winst of verlies door over- of onderbezetting: W &lt; N geeft negatief BezR (onderbezetting), W &gt; N positief.","back_en":"<strong>BezR = (W − N) × (C/N)</strong>. Gain or loss from over/under-utilisation of capacity: W &lt; N gives a negative result (under-capacity), W &gt; N a positive one.","back_fr":"<strong>BezR = (W − N) × (C/N)</strong>. Gain ou perte dû à la sous- ou suroccupation: W &lt; N donne un résultat négatif (sous-occupation), W &gt; N un résultat positif."},{"cat":"mac","front_nl":"Formule: bedrijfsresultaat (BedR) bij absorption costing ?","front_en":"Formula: operating result under absorption costing?","front_fr":"Formule: résultat d'exploitation en coût complet ?","back_nl":"<strong>BedR = VR + BezR</strong>. Verkoopwinst plus het bezettingsresultaat van de fabriek.","back_en":"<strong>BedR = VR + BezR</strong>. Sales profit plus the capacity result of the factory.","back_fr":"<strong>BedR = VR + BezR</strong>. Profit sur ventes plus le résultat d'occupation de l'usine."},{"cat":"mac","front_nl":"Definitie + formule: dekkingsbijdrage (DB) ?","front_en":"Definition + formula: contribution margin (DB)?","front_fr":"Définition + formule: marge sur coûts variables (DB) ?","back_nl":"<strong>DB per eenheid = p − v</strong>; totale DB = (p − v) × afzet. Het bedrag dat elke verkochte eenheid bijdraagt aan de dekking van de vaste kosten.","back_en":"<strong>CM per unit = p − v</strong>; total CM = (p − v) × sales. The amount each unit sold contributes towards covering fixed costs.","back_fr":"<strong>DB par unité = p − v</strong>; DB totale = (p − v) × ventes. Le montant que chaque unité vendue apporte à la couverture des coûts fixes."},{"cat":"mac","front_nl":"Formule: netto bedrijfsresultaat bij direct costing ?","front_en":"Formula: net operating result under direct costing?","front_fr":"Formule: résultat net en direct costing ?","back_nl":"<strong>NBR = Totale DB − C</strong>. Wat na het dekken van alle vaste kosten C overblijft, is winst (of verlies als DB &lt; C).","back_en":"<strong>NBR = Total CM − C</strong>. What remains after covering all fixed costs C is profit (or loss if CM &lt; C).","back_fr":"<strong>NBR = DB totale − C</strong>. Ce qui reste après couverture des coûts fixes C est le bénéfice (ou la perte si DB &lt; C)."},{"cat":"mac","front_nl":"Formule: verschil tussen AC- en DC-resultaat ?","front_en":"Formula: difference between AC and DC results?","front_fr":"Formule: écart entre résultat AC et DC ?","back_nl":"<strong>AC − DC = (W − afzet) × (C/N)</strong>. Voorraadstijging (W &gt; afzet) maakt AC &gt; DC omdat vaste kosten in de voorraad \"verstopt\" zitten; bij W = afzet zijn beide gelijk.","back_en":"<strong>AC − DC = (W − sales) × (C/N)</strong>. Inventory build-up (W &gt; sales) makes AC &gt; DC because fixed costs are \"hidden\" in stock; if W = sales both are equal.","back_fr":"<strong>AC − DC = (W − ventes) × (C/N)</strong>. Une hausse de stock (W &gt; ventes) rend AC &gt; DC car des coûts fixes sont \"cachés\" dans le stock; si W = ventes, les deux sont égaux."},{"cat":"mac","front_nl":"Regel: incidentele order bij vrije capaciteit — vergelijk met k of met v ?","front_en":"Rule: one-off order with spare capacity — compare with k or with v?","front_fr":"Règle: commande exceptionnelle avec capacité libre — comparer à k ou à v ?","back_nl":"Vergelijk p met <strong>v</strong>, nooit met k: de vaste kosten zijn al gedekt en dus niet relevant. <strong>Extra winst = (p − v) × extra eenheden</strong>, winstgevend zolang p &gt; v.","back_en":"Compare p with <strong>v</strong>, never with k: fixed costs are already covered and therefore irrelevant. <strong>Extra profit = (p − v) × extra units</strong>, profitable as long as p &gt; v.","back_fr":"Comparez p à <strong>v</strong>, jamais à k: les coûts fixes sont déjà couverts donc non pertinents. <strong>Profit supplémentaire = (p − v) × unités supplémentaires</strong>, rentable tant que p &gt; v."},{"cat":"mac","front_nl":"Formule: opslagmethode (primitieve methode) ?","front_en":"Formula: overhead surcharge (primitive) method?","front_fr":"Formule: méthode des coefficients (méthode primitive) ?","back_nl":"<strong>Opslag% = (totale indirecte kosten / totale directe kosten) × 100</strong>; kp = directe kosten × (1 + opslag%/100). Eén percentage verdeelt alle indirecte kosten over de producten.","back_en":"<strong>Surcharge% = (total indirect costs / total direct costs) × 100</strong>; cost price = direct costs × (1 + surcharge%/100). One single rate spreads all indirect costs over products.","back_fr":"<strong>Taux% = (coûts indirects totaux / coûts directs totaux) × 100</strong>; coût de revient = coûts directs × (1 + taux%/100). Un seul pourcentage répartit tous les coûts indirects."},{"cat":"mac","front_nl":"Definitie: verfijnde opslagmethode ?","front_en":"Definition: refined surcharge method?","front_fr":"Définition: méthode des coefficients affinée ?","back_nl":"Indirecte kosten worden gesplitst in categorieën met elk een <strong>eigen opslagpercentage</strong> (materiaalopslag op M, loonopslag op L, overige op M+L): kp = M + L + M×mat% + L×loon% + (M+L)×overig%.","back_en":"Indirect costs are split into categories, each with its <strong>own surcharge rate</strong> (material rate on M, labour rate on L, other on M+L): cost = M + L + M×mat% + L×lab% + (M+L)×other%.","back_fr":"Les coûts indirects sont scindés en catégories avec chacune <strong>son propre taux</strong> (taux matières sur M, taux main-d'œuvre sur L, autres sur M+L): coût = M + L + M×mat% + L×mo% + (M+L)×autres%."},{"cat":"mac","front_nl":"Definitie + formule: Activity-Based Costing (ABC) ?","front_en":"Definition + formula: Activity-Based Costing (ABC)?","front_fr":"Définition + formule: comptabilité par activités (ABC) ?","back_nl":"Producten verbruiken <strong>activiteiten</strong>, activiteiten verbruiken kosten. <strong>Tarief = poolkosten / totale kostendrijver-eenheden</strong>; productaandeel = tarief × verbruikte drijvereenheden. Onthult dat kleine batches duurder zijn.","back_en":"Products consume <strong>activities</strong>, activities consume costs. <strong>Rate = pool costs / total cost-driver units</strong>; product share = rate × driver units used. Reveals that small batches are more expensive.","back_fr":"Les produits consomment des <strong>activités</strong>, les activités consomment des coûts. <strong>Taux = coûts du pool / unités totales d'inducteur</strong>; part du produit = taux × unités consommées. Révèle que les petits lots coûtent plus cher."},{"cat":"mac","front_nl":"Formule: break-even punt (BEP) in eenheden en in omzet ?","front_en":"Formula: break-even point in units and in revenue?","front_fr":"Formule: seuil de rentabilité en unités et en chiffre d'affaires ?","back_nl":"<strong>BEP_afzet = C / (p − v)</strong> en <strong>BEP_omzet = BEP_afzet × p = C / CM%</strong>. Vaste kosten gedeeld door de contributiemarge per eenheid geeft het aantal eenheden om quitte te spelen.","back_en":"<strong>BEP_units = C / (p − v)</strong> and <strong>BEP_revenue = BEP_units × p = C / CM%</strong>. Fixed costs divided by the unit contribution margin gives the units needed to break even.","back_fr":"<strong>SR_unités = C / (p − v)</strong> et <strong>SR_CA = SR_unités × p = C / CM%</strong>. Les coûts fixes divisés par la marge unitaire donnent le nombre d'unités pour atteindre l'équilibre."},{"cat":"mac","front_nl":"Formule: benodigde afzet voor een winstdoel ?","front_en":"Formula: required sales for a target profit?","front_fr":"Formule: ventes nécessaires pour un objectif de bénéfice ?","back_nl":"<strong>q_doel = (C + gewenste winst) / (p − v)</strong>. Behandel de gewenste winst als een extra \"vaste kost\" die ook gedekt moet worden.","back_en":"<strong>q_target = (C + desired profit) / (p − v)</strong>. Treat the desired profit as an extra \"fixed cost\" that must also be covered.","back_fr":"<strong>q_cible = (C + bénéfice souhaité) / (p − v)</strong>. Traitez le bénéfice souhaité comme un \"coût fixe\" supplémentaire à couvrir."},{"cat":"mac","front_nl":"Formule + definitie: veiligheidsmarge (VM%) ?","front_en":"Formula + definition: margin of safety?","front_fr":"Formule + définition: marge de sécurité ?","back_nl":"<strong>VM% = (werkelijke afzet − BEP_afzet) / werkelijke afzet × 100</strong>. Met hoeveel procent mag de afzet dalen vooraleer je verlies maakt — jouw buffer.","back_en":"<strong>MoS% = (actual sales − BEP_units) / actual sales × 100</strong>. The percentage by which sales may drop before you make a loss — your buffer.","back_fr":"<strong>MS% = (ventes réelles − SR_unités) / ventes réelles × 100</strong>. Le pourcentage de baisse des ventes supportable avant de faire une perte — votre coussin de sécurité."},{"cat":"mac","front_nl":"Definitie: ex-ante vs ex-post begroting + kostenverschil ?","front_en":"Definition: ex-ante vs ex-post budget + cost variance?","front_fr":"Définition: budget ex-ante vs ex-post + écart de coûts ?","back_nl":"<strong>Ex-ante</strong> = oorspronkelijk budget vóór de periode; <strong>ex-post = norm per eenheid × werkelijk volume</strong>. Kostenverschil = werkelijke kosten − ex-post (positief = nadelig). Vergelijk werkelijke kosten nooit rechtstreeks met ex-ante bij ander volume!","back_en":"<strong>Ex-ante</strong> = original budget set before the period; <strong>ex-post = standard per unit × actual volume</strong>. Cost variance = actual costs − ex-post (positive = unfavorable). Never compare actual costs directly with the ex-ante budget when volume differs!","back_fr":"<strong>Ex-ante</strong> = budget initial établi avant la période; <strong>ex-post = norme unitaire × volume réel</strong>. Écart de coûts = coûts réels − ex-post (positif = défavorable). Ne comparez jamais les coûts réels directement à l'ex-ante si le volume diffère !"},{"cat":"omi","front_nl":"Definitie: gegevens vs informatie ?","front_en":"Definition: data vs information?","front_fr":"Définition: données vs information ?","back_nl":"<strong>Gegevens</strong> zijn ruwe, objectieve feiten (cijfers, namen) zonder context; <strong>informatie</strong> zijn gegevens die verwerkt en betekenisvol gemaakt zijn zodat ze beslissingen ondersteunen.","back_en":"<strong>Data</strong> are raw, objective facts (numbers, names) without context; <strong>information</strong> is data that has been processed and given meaning so it supports decisions.","back_fr":"Les <strong>données</strong> sont des faits bruts et objectifs (chiffres, noms) sans contexte; l'<strong>information</strong> est constituée de données traitées et dotées de sens pour soutenir les décisions."},{"cat":"omi","front_nl":"Wat betekent GIGO ?","front_en":"What does GIGO mean?","front_fr":"Que signifie GIGO ?","back_nl":"<strong>Garbage In, Garbage Out</strong>: als de ingevoerde gegevens fout of onvolledig zijn, is de output van het informatiesysteem ook waardeloos — hoe goed het systeem ook is.","back_en":"<strong>Garbage In, Garbage Out</strong>: if the input data is wrong or incomplete, the system's output is worthless too — no matter how good the system is.","back_fr":"<strong>Garbage In, Garbage Out</strong>: si les données saisies sont erronées ou incomplètes, la sortie du système est elle aussi sans valeur — quelle que soit la qualité du système."},{"cat":"omi","front_nl":"Definitie: stuurinformatie vs verantwoordingsinformatie ?","front_en":"Definition: steering information vs accountability information?","front_fr":"Définition: information de pilotage vs information de justification ?","back_nl":"<strong>Stuurinformatie</strong> stroomt naar beneden: het management stuurt er de uitvoering mee bij (doelen, normen). <strong>Verantwoordingsinformatie</strong> stroomt naar boven: de uitvoering rapporteert over de behaalde resultaten.","back_en":"<strong>Steering information</strong> flows downwards: management uses it to direct operations (goals, standards). <strong>Accountability information</strong> flows upwards: operations report back on results achieved.","back_fr":"L'<strong>information de pilotage</strong> descend: la direction l'utilise pour orienter l'exécution (objectifs, normes). L'<strong>information de justification</strong> remonte: l'exécution rend compte des résultats obtenus."},{"cat":"omi","front_nl":"Definitie: kengetal vs streefgetal ?","front_en":"Definition: key figure vs target figure?","front_fr":"Définition: indicateur clé vs valeur cible ?","back_nl":"Een <strong>kengetal</strong> vat een prestatie samen in één getal (bv. ziekteverzuim 4%); een <strong>streefgetal</strong> is de gewenste waarde ervan. Een afwijking tussen beide is een signaal om bij te sturen.","back_en":"A <strong>key figure</strong> summarises a performance in one number (e.g. absenteeism 4%); a <strong>target figure</strong> is its desired value. A deviation between the two is a signal to take action.","back_fr":"Un <strong>indicateur clé</strong> résume une performance en un chiffre (ex. absentéisme 4 %); la <strong>valeur cible</strong> en est la valeur souhaitée. Un écart entre les deux est un signal pour agir."},{"cat":"omi","front_nl":"De drie soorten bedrijfsprocessen ?","front_en":"The three types of business processes?","front_fr":"Les trois types de processus d'entreprise ?","back_nl":"<strong>Primair</strong> (kernactiviteiten, directe klantwaarde: inkoop, productie, verkoop), <strong>secundair</strong> (ondersteunend: HR, IT, schoonmaak) en <strong>bestuurlijk</strong> (sturing, planning en controle door de directie).","back_en":"<strong>Primary</strong> (core activities, direct customer value: purchasing, production, sales), <strong>secondary</strong> (supporting: HR, IT, cleaning) and <strong>managerial</strong> (steering, planning and control by management).","back_fr":"<strong>Primaires</strong> (cœur de métier, valeur directe pour le client: achats, production, ventes), <strong>secondaires</strong> (soutien: RH, IT, nettoyage) et <strong>de pilotage</strong> (direction, planification et contrôle)."},{"cat":"omi","front_nl":"Verschil: impuls vs trigger ?","front_en":"Difference: impulse vs trigger?","front_fr":"Différence: impulsion vs déclencheur ?","back_nl":"De <strong>impuls</strong> is de prikkel uit de omgeving (bv. een reclame, een hittegolf); de <strong>trigger</strong> is de directe aanleiding die het bedrijfsproces effectief start (bv. de bestelling, stock onder minimum).","back_en":"The <strong>impulse</strong> is the stimulus from the environment (e.g. an advert, a heat wave); the <strong>trigger</strong> is the direct cause that actually starts the business process (e.g. the order, stock below minimum).","back_fr":"L'<strong>impulsion</strong> est le stimulus de l'environnement (ex. une publicité, une canicule); le <strong>déclencheur</strong> est la cause directe qui lance effectivement le processus (ex. la commande, stock sous le minimum)."},{"cat":"omi","front_nl":"De drie niveaus van informatie in een organisatie ?","front_en":"The three levels of information in an organisation?","front_fr":"Les trois niveaux d'information dans une organisation ?","back_nl":"<strong>Operationeel</strong> (uitvoerend personeel, real-time, zeer gedetailleerd), <strong>management</strong> (afdelingsmanagers, periodiek, trends en afwijkingen) en <strong>strategisch/stuur</strong> (directie, lange termijn, samengevat).","back_en":"<strong>Operational</strong> (staff on the floor, real-time, very detailed), <strong>management</strong> (department managers, periodic, trends and deviations) and <strong>strategic/steering</strong> (top management, long-term, summarised).","back_fr":"<strong>Opérationnel</strong> (personnel d'exécution, temps réel, très détaillé), <strong>management</strong> (responsables, périodique, tendances et écarts) et <strong>stratégique/pilotage</strong> (direction, long terme, synthétisé)."},{"cat":"omi","front_nl":"Wat toont een globaal systeemschema (GSS) ?","front_en":"What does a global system schema (GSS) show?","front_fr":"Que montre un schéma global de système (GSS) ?","back_nl":"Een overzicht van het informatiesysteem op hoog niveau: de <strong>processen</strong>, de <strong>gegevensverzamelingen (opslag)</strong>, de <strong>externe partijen</strong> en de <strong>informatiestromen (pijlen)</strong> ertussen — zonder technische details.","back_en":"A high-level overview of the information system: the <strong>processes</strong>, <strong>data stores</strong>, <strong>external parties</strong> and the <strong>information flows (arrows)</strong> between them — without technical detail.","back_fr":"Une vue d'ensemble de haut niveau du système d'information: les <strong>processus</strong>, les <strong>stockages de données</strong>, les <strong>parties externes</strong> et les <strong>flux d'information (flèches)</strong> entre eux — sans détails techniques."},{"cat":"omi","front_nl":"De vier symbolen van een dataflowdiagram (DFD) ?","front_en":"The four symbols of a data flow diagram (DFD)?","front_fr":"Les quatre symboles d'un diagramme de flux de données (DFD) ?","back_nl":"<strong>Proces</strong> (cirkel/afgeronde rechthoek: verwerkt gegevens), <strong>gegevensopslag</strong> (open rechthoek), <strong>externe entiteit</strong> (vierkant: bron of bestemming buiten het systeem) en <strong>gegevensstroom</strong> (pijl).","back_en":"<strong>Process</strong> (circle/rounded rectangle: transforms data), <strong>data store</strong> (open rectangle), <strong>external entity</strong> (square: source or destination outside the system) and <strong>data flow</strong> (arrow).","back_fr":"<strong>Processus</strong> (cercle/rectangle arrondi: transforme les données), <strong>stockage</strong> (rectangle ouvert), <strong>entité externe</strong> (carré: source ou destination hors système) et <strong>flux de données</strong> (flèche)."},{"cat":"omi","front_nl":"Definitie: IaaS ?","front_en":"Definition: IaaS?","front_fr":"Définition: IaaS ?","back_nl":"<strong>Infrastructure as a Service</strong>: je huurt ruwe IT-infrastructuur (servers, opslag, netwerk) in de cloud; jij beheert zelf het besturingssysteem en de software. Bv. Amazon EC2.","back_en":"<strong>Infrastructure as a Service</strong>: you rent raw IT infrastructure (servers, storage, network) in the cloud; you manage the operating system and software yourself. E.g. Amazon EC2.","back_fr":"<strong>Infrastructure as a Service</strong>: on loue l'infrastructure IT brute (serveurs, stockage, réseau) dans le cloud; on gère soi-même le système d'exploitation et les logiciels. Ex. Amazon EC2."},{"cat":"omi","front_nl":"Definitie: PaaS ?","front_en":"Definition: PaaS?","front_fr":"Définition: PaaS ?","back_nl":"<strong>Platform as a Service</strong>: de provider levert infrastructuur én platform (besturingssysteem, databases, ontwikkeltools); jij bouwt en beheert enkel je eigen applicaties. Bv. Microsoft Azure App Service.","back_en":"<strong>Platform as a Service</strong>: the provider delivers infrastructure plus platform (OS, databases, development tools); you only build and manage your own applications. E.g. Microsoft Azure App Service.","back_fr":"<strong>Platform as a Service</strong>: le fournisseur livre l'infrastructure et la plateforme (OS, bases de données, outils de développement); vous ne gérez que vos propres applications. Ex. Microsoft Azure App Service."},{"cat":"omi","front_nl":"Definitie: SaaS ?","front_en":"Definition: SaaS?","front_fr":"Définition: SaaS ?","back_nl":"<strong>Software as a Service</strong>: kant-en-klare software via internet, de provider beheert alles; jij gebruikt de toepassing gewoon via de browser. Bv. Gmail, Office 365, Salesforce.","back_en":"<strong>Software as a Service</strong>: ready-to-use software over the internet, the provider manages everything; you simply use the application via the browser. E.g. Gmail, Office 365, Salesforce.","back_fr":"<strong>Software as a Service</strong>: logiciel prêt à l'emploi via Internet, le fournisseur gère tout; vous utilisez simplement l'application via le navigateur. Ex. Gmail, Office 365, Salesforce."},{"cat":"omi","front_nl":"Definitie: TPS ?","front_en":"Definition: TPS?","front_fr":"Définition: TPS ?","back_nl":"<strong>Transaction Processing System</strong>: registreert en verwerkt de dagelijkse routinetransacties op operationeel niveau (kassasysteem, bestellingen, loonverwerking).","back_en":"<strong>Transaction Processing System</strong>: records and processes daily routine transactions at the operational level (point-of-sale, orders, payroll).","back_fr":"<strong>Transaction Processing System</strong>: enregistre et traite les transactions routinières quotidiennes au niveau opérationnel (caisse, commandes, paie)."},{"cat":"omi","front_nl":"Definitie: MIS ?","front_en":"Definition: MIS?","front_fr":"Définition: MIS ?","back_nl":"<strong>Management Information System</strong>: vat de gegevens uit de TPS samen tot periodieke rapporten voor middenkader-managers (weekrapporten, vergelijkingen met doelstellingen).","back_en":"<strong>Management Information System</strong>: summarises TPS data into periodic reports for middle managers (weekly reports, comparisons with targets).","back_fr":"<strong>Management Information System</strong>: synthétise les données du TPS en rapports périodiques pour les cadres intermédiaires (rapports hebdomadaires, comparaisons avec les objectifs)."},{"cat":"omi","front_nl":"Definitie: DSS ?","front_en":"Definition: DSS?","front_fr":"Définition: DSS ?","back_nl":"<strong>Decision Support System</strong>: ondersteunt niet-routineuze beslissingen met modellen, simulaties en wat-als-analyses (bv. \"wat als we de prijs 10% verhogen?\").","back_en":"<strong>Decision Support System</strong>: supports non-routine decisions using models, simulations and what-if analyses (e.g. \"what if we raise the price by 10%?\").","back_fr":"<strong>Decision Support System</strong>: soutient les décisions non routinières grâce à des modèles, simulations et analyses \"what-if\" (ex. \"et si on augmentait le prix de 10 % ?\")."},{"cat":"omi","front_nl":"Definitie: ERP ?","front_en":"Definition: ERP?","front_fr":"Définition: ERP ?","back_nl":"<strong>Enterprise Resource Planning</strong>: één geïntegreerd softwarepakket met één centrale database voor alle afdelingen (verkoop, voorraad, boekhouding, HR), zodat iedereen met dezelfde actuele gegevens werkt. Bv. SAP.","back_en":"<strong>Enterprise Resource Planning</strong>: one integrated software package with a single central database for all departments (sales, inventory, accounting, HR), so everyone works with the same up-to-date data. E.g. SAP.","back_fr":"<strong>Enterprise Resource Planning</strong>: un progiciel intégré avec une base de données centrale unique pour tous les départements (ventes, stocks, comptabilité, RH), pour que tous travaillent avec les mêmes données à jour. Ex. SAP."},{"cat":"omi","front_nl":"Definitie: DMS ?","front_en":"Definition: DMS?","front_fr":"Définition: DMS ?","back_nl":"<strong>Document Management System</strong>: systeem voor het digitaal opslaan, versioneren, terugvinden en delen van documenten, met toegangsrechten en zoekfuncties.","back_en":"<strong>Document Management System</strong>: a system for digitally storing, versioning, retrieving and sharing documents, with access rights and search functions.","back_fr":"<strong>Document Management System</strong>: système de stockage numérique, de gestion des versions, de recherche et de partage de documents, avec droits d'accès et fonctions de recherche."},{"cat":"omi","front_nl":"Definitie: EDI ?","front_en":"Definition: EDI?","front_fr":"Définition: EDI ?","back_nl":"<strong>Electronic Data Interchange</strong>: gestructureerde, gestandaardiseerde elektronische uitwisseling van bedrijfsdocumenten (bestellingen, facturen) tussen computersystemen van bedrijven, zonder menselijke tussenkomst.","back_en":"<strong>Electronic Data Interchange</strong>: structured, standardised electronic exchange of business documents (orders, invoices) between companies' computer systems, without human intervention.","back_fr":"<strong>Electronic Data Interchange</strong>: échange électronique structuré et normalisé de documents commerciaux (commandes, factures) entre systèmes informatiques d'entreprises, sans intervention humaine."},{"cat":"omi","front_nl":"Verschil: batchverwerking vs real-time verwerking ?","front_en":"Difference: batch processing vs real-time processing?","front_fr":"Différence: traitement par lots vs traitement en temps réel ?","back_nl":"<strong>Batch</strong>: transacties worden verzameld en periodiek samen verwerkt (bv. loonverwerking 's nachts). <strong>Real-time</strong>: elke transactie wordt onmiddellijk verwerkt en de gegevens zijn meteen actueel (bv. ticketreservatie).","back_en":"<strong>Batch</strong>: transactions are collected and processed together periodically (e.g. payroll at night). <strong>Real-time</strong>: each transaction is processed immediately and data is instantly up to date (e.g. ticket booking).","back_fr":"<strong>Par lots</strong>: les transactions sont collectées puis traitées ensemble périodiquement (ex. paie la nuit). <strong>Temps réel</strong>: chaque transaction est traitée immédiatement et les données sont aussitôt à jour (ex. réservation de billets)."},{"cat":"omi","front_nl":"Definitie: redundantie (in gegevensopslag) ?","front_en":"Definition: redundancy (in data storage)?","front_fr":"Définition: redondance (dans le stockage de données) ?","back_nl":"Dezelfde gegevens worden <strong>meerdere keren opgeslagen</strong> op verschillende plaatsen (bv. het adres van een klant in drie bestanden). Verspilt opslag en leidt makkelijk tot inconsistentie.","back_en":"The same data is <strong>stored multiple times</strong> in different places (e.g. a customer's address in three files). It wastes storage and easily leads to inconsistency.","back_fr":"Les mêmes données sont <strong>stockées plusieurs fois</strong> à différents endroits (ex. l'adresse d'un client dans trois fichiers). Gaspille du stockage et mène facilement à l'incohérence."},{"cat":"omi","front_nl":"Definitie: inconsistentie (in gegevens) ?","front_en":"Definition: inconsistency (in data)?","front_fr":"Définition: incohérence (dans les données) ?","back_nl":"Verschillende kopieën van hetzelfde gegeven <strong>spreken elkaar tegen</strong> omdat slechts één kopie werd bijgewerkt (bv. oud adres in het ene bestand, nieuw adres in het andere). Typisch gevolg van redundantie.","back_en":"Different copies of the same data <strong>contradict each other</strong> because only one copy was updated (e.g. old address in one file, new address in another). A typical consequence of redundancy.","back_fr":"Différentes copies de la même donnée <strong>se contredisent</strong> parce qu'une seule copie a été mise à jour (ex. ancienne adresse dans un fichier, nouvelle dans un autre). Conséquence typique de la redondance."},{"cat":"omi","front_nl":"Definitie: 1-n relatie (databank) ?","front_en":"Definition: 1-n (one-to-many) relationship?","front_fr":"Définition: relation 1-n (un-à-plusieurs) ?","back_nl":"Eén record in tabel A hoort bij <strong>meerdere</strong> records in tabel B, maar elk B-record bij precies één A-record (één klant heeft meerdere bestellingen). Gerealiseerd via een <strong>vreemde sleutel</strong> in de n-tabel.","back_en":"One record in table A relates to <strong>many</strong> records in table B, but each B record to exactly one A record (one customer has many orders). Implemented with a <strong>foreign key</strong> in the many-side table.","back_fr":"Un enregistrement de la table A correspond à <strong>plusieurs</strong> enregistrements de la table B, mais chaque B à exactement un A (un client a plusieurs commandes). Réalisé via une <strong>clé étrangère</strong> dans la table côté n."},{"cat":"omi","front_nl":"Definitie: n-m relatie en hoe los je ze op ?","front_en":"Definition: n-m (many-to-many) relationship and how to resolve it?","front_fr":"Définition: relation n-m (plusieurs-à-plusieurs) et comment la résoudre ?","back_nl":"Records in beide tabellen kunnen bij <strong>meerdere</strong> records van de andere tabel horen (studenten ↔ vakken). Oplossing: een <strong>tussentabel</strong> die twee 1-n relaties creëert.","back_en":"Records in both tables can relate to <strong>many</strong> records in the other table (students ↔ courses). Solution: a <strong>junction (linking) table</strong> that creates two 1-n relationships.","back_fr":"Les enregistrements des deux tables peuvent correspondre à <strong>plusieurs</strong> enregistrements de l'autre (étudiants ↔ cours). Solution: une <strong>table de liaison</strong> qui crée deux relations 1-n."},{"cat":"omi","front_nl":"Definitie: primaire sleutel ?","front_en":"Definition: primary key?","front_fr":"Définition: clé primaire ?","back_nl":"Een veld (of combinatie van velden) dat elk record <strong>uniek identificeert</strong>; mag nooit leeg zijn en nooit dubbel voorkomen (bv. klantnummer, rijksregisternummer).","back_en":"A field (or combination of fields) that <strong>uniquely identifies</strong> each record; it may never be empty or duplicated (e.g. customer number, national register number).","back_fr":"Un champ (ou une combinaison de champs) qui <strong>identifie de manière unique</strong> chaque enregistrement; ne peut jamais être vide ni dupliqué (ex. numéro de client, numéro de registre national)."},{"cat":"omi","front_nl":"Definitie: booleaans zoeken ?","front_en":"Definition: Boolean searching?","front_fr":"Définition: recherche booléenne ?","back_nl":"Zoeken met de operatoren <strong>AND</strong> (beide termen vereist, verkleint resultaat), <strong>OR</strong> (één van beide volstaat, vergroot resultaat) en <strong>NOT</strong> (sluit een term uit).","back_en":"Searching with the operators <strong>AND</strong> (both terms required, narrows results), <strong>OR</strong> (either term suffices, broadens results) and <strong>NOT</strong> (excludes a term).","back_fr":"Recherche avec les opérateurs <strong>AND</strong> (les deux termes requis, réduit les résultats), <strong>OR</strong> (l'un des deux suffit, élargit les résultats) et <strong>NOT</strong> (exclut un terme)."},{"cat":"omi","front_nl":"De 5 V's van big data ?","front_en":"The 5 V's of big data?","front_fr":"Les 5 V du big data ?","back_nl":"<strong>Volume</strong> (enorme hoeveelheden), <strong>Velocity</strong> (snelheid van aanmaak en verwerking), <strong>Variety</strong> (verscheidenheid: tekst, beeld, sensoren), <strong>Veracity</strong> (betrouwbaarheid) en <strong>Value</strong> (waarde voor de organisatie).","back_en":"<strong>Volume</strong> (huge amounts), <strong>Velocity</strong> (speed of creation and processing), <strong>Variety</strong> (diversity: text, images, sensors), <strong>Veracity</strong> (reliability) and <strong>Value</strong> (value for the organisation).","back_fr":"<strong>Volume</strong> (quantités énormes), <strong>Vélocité</strong> (vitesse de création et de traitement), <strong>Variété</strong> (diversité: texte, images, capteurs), <strong>Véracité</strong> (fiabilité) et <strong>Valeur</strong> (valeur pour l'organisation)."},{"cat":"omi","front_nl":"De vier perspectieven van de balanced scorecard ?","front_en":"The four perspectives of the balanced scorecard?","front_fr":"Les quatre perspectives du tableau de bord prospectif ?","back_nl":"<strong>Financieel</strong> (wat verwachten aandeelhouders?), <strong>klant</strong> (hoe zien klanten ons?), <strong>interne processen</strong> (waar moeten we uitblinken?) en <strong>leren &amp; groei/innovatie</strong> (hoe blijven we verbeteren?).","back_en":"<strong>Financial</strong> (what do shareholders expect?), <strong>customer</strong> (how do customers see us?), <strong>internal processes</strong> (where must we excel?) and <strong>learning &amp; growth/innovation</strong> (how do we keep improving?).","back_fr":"<strong>Financière</strong> (qu'attendent les actionnaires ?), <strong>client</strong> (comment les clients nous voient-ils ?), <strong>processus internes</strong> (où devons-nous exceller ?) et <strong>apprentissage &amp; croissance/innovation</strong> (comment continuer à nous améliorer ?)."},{"cat":"omi","front_nl":"De drie factoren van multifactorauthenticatie (MFA) ?","front_en":"The three factors of multi-factor authentication (MFA)?","front_fr":"Les trois facteurs de l'authentification multifacteur (MFA) ?","back_nl":"Iets dat je <strong>weet</strong> (wachtwoord, pincode), iets dat je <strong>hebt</strong> (smartphone, kaartlezer, token) en iets dat je <strong>bent</strong> (biometrie: vingerafdruk, gezicht). MFA combineert minstens twee verschillende factoren.","back_en":"Something you <strong>know</strong> (password, PIN), something you <strong>have</strong> (smartphone, card reader, token) and something you <strong>are</strong> (biometrics: fingerprint, face). MFA combines at least two different factors.","back_fr":"Quelque chose que vous <strong>savez</strong> (mot de passe, code PIN), que vous <strong>possédez</strong> (smartphone, lecteur de carte, token) et que vous <strong>êtes</strong> (biométrie: empreinte, visage). La MFA combine au moins deux facteurs différents."},{"cat":"omi","front_nl":"Wat is het spinmodel ?","front_en":"What is the spider model?","front_fr":"Qu'est-ce que le modèle de l'araignée ?","back_nl":"De organisatie als <strong>spin in een web</strong> van externe partijen (klanten, leveranciers, overheid, banken): met elke partij lopen er <strong>informatiestromen</strong> heen en terug die het informatiesysteem moet ondersteunen.","back_en":"The organisation as a <strong>spider in a web</strong> of external parties (customers, suppliers, government, banks): information flows run back and forth with each party, and the information system must support them.","back_fr":"L'organisation comme une <strong>araignée dans une toile</strong> de parties externes (clients, fournisseurs, État, banques): des <strong>flux d'information</strong> circulent dans les deux sens avec chaque partie, et le système d'information doit les soutenir."},{"cat":"omi","front_nl":"Wat is het besturingsmodel (de regelkring) ?","front_en":"What is the control model (control loop)?","front_fr":"Qu'est-ce que le modèle de pilotage (boucle de régulation) ?","back_nl":"Het <strong>besturend orgaan</strong> stuurt het <strong>bestuurd systeem</strong> via een regelkring: norm bepalen → <strong>meten</strong> → vergelijken met de norm → <strong>bijsturen</strong> bij afwijking. Het informatiesysteem levert daarvoor de meet- en stuurinformatie.","back_en":"The <strong>controlling body</strong> steers the <strong>controlled system</strong> through a control loop: set the standard → <strong>measure</strong> → compare with the standard → <strong>adjust</strong> when there is a deviation. The information system supplies the measurement and steering information.","back_fr":"L'<strong>organe de pilotage</strong> dirige le <strong>système piloté</strong> via une boucle de régulation: fixer la norme → <strong>mesurer</strong> → comparer à la norme → <strong>corriger</strong> en cas d'écart. Le système d'information fournit l'information de mesure et de pilotage."},{"cat":"omi","front_nl":"Definitie: IoT (Internet of Things) ?","front_en":"Definition: IoT (Internet of Things)?","front_fr":"Définition: IoT (Internet des objets) ?","back_nl":"Fysieke apparaten die <strong>zelf data verzamelen en versturen</strong> via internet, zonder menselijke tussenkomst (slimme koelkast, sensoren in een fabriek).","back_en":"Physical devices that <strong>collect and transmit data by themselves</strong> over the internet, without human intervention (smart fridge, factory sensors).","back_fr":"Des appareils physiques qui <strong>collectent et transmettent eux-mêmes des données</strong> via Internet, sans intervention humaine (réfrigérateur intelligent, capteurs en usine)."},{"cat":"omi","front_nl":"Verschil: profit vs non-profit organisatie ?","front_en":"Difference: profit vs non-profit organisation?","front_fr":"Différence: organisation à but lucratif vs sans but lucratif ?","back_nl":"Een <strong>profitorganisatie</strong> streeft naar winst voor de eigenaars (Colruyt); een <strong>non-profit</strong> heeft een maatschappelijk doel en keert geen winst uit aan aandeelhouders (Rode Kruis, KU Leuven).","back_en":"A <strong>profit organisation</strong> aims to make money for its owners (Colruyt); a <strong>non-profit</strong> has a social goal and does not distribute profits to shareholders (Red Cross, KU Leuven).","back_fr":"Une <strong>organisation à but lucratif</strong> vise le profit pour ses propriétaires (Colruyt); une <strong>ASBL</strong> poursuit un objectif social et ne distribue pas de bénéfices (Croix-Rouge, KU Leuven)."},{"cat":"omi","front_nl":"Wat is een bedrijfsproces (als transformatie) ?","front_en":"What is a business process (as a transformation)?","front_fr":"Qu'est-ce qu'un processus d'entreprise (comme transformation) ?","back_nl":"Een reeks activiteiten die samen een doel bereiken: <strong>invoer</strong> (grondstoffen, informatie) → <strong>activiteiten</strong> → <strong>uitvoer</strong> (product, dienst, rapport). Elk proces start met een trigger.","back_en":"A series of activities that together achieve a goal: <strong>input</strong> (materials, information) → <strong>activities</strong> → <strong>output</strong> (product, service, report). Every process starts with a trigger.","back_fr":"Une série d'activités qui atteignent ensemble un objectif: <strong>entrée</strong> (matières, informations) → <strong>activités</strong> → <strong>sortie</strong> (produit, service, rapport). Tout processus démarre par un déclencheur."},{"cat":"omi","front_nl":"Verschil: databank vs losse bestanden ?","front_en":"Difference: database vs separate files?","front_fr":"Différence: base de données vs fichiers séparés ?","back_nl":"Een <strong>databank</strong> slaat gegevens centraal en eenmalig op met gekoppelde tabellen, waardoor <strong>redundantie en inconsistentie</strong> vermeden worden; losse bestanden per afdeling leiden tot dubbele en tegenstrijdige gegevens.","back_en":"A <strong>database</strong> stores data centrally and only once in linked tables, avoiding <strong>redundancy and inconsistency</strong>; separate files per department lead to duplicated and contradictory data.","back_fr":"Une <strong>base de données</strong> stocke les données de façon centrale et unique dans des tables liées, évitant <strong>redondance et incohérence</strong>; des fichiers séparés par département mènent à des données dupliquées et contradictoires."}];
let flashDeck = [], flashIdx = 0, flashFlipped = false;

function openFlash(){
 if(!FLASHCARDS.length){ alert(lang==='fr'?'Flashcards en cours de chargement…':'Flashcards loading…'); return; }
 flashDeck = [...FLASHCARDS].sort(()=>Math.random()-0.5);
 flashIdx = 0;
 document.getElementById('flashOverlay').style.display = 'flex';
 showFlash();
}
function closeFlash(){ document.getElementById('flashOverlay').style.display = 'none'; }
function showFlash(){
 const c = flashDeck[flashIdx];
 flashFlipped = false;
 document.getElementById('flashInner').classList.remove('flipped');
 const f = (k)=> lang==='fr'?c[k+'_fr']:lang==='en'?c[k+'_en']:c[k+'_nl'];
 document.getElementById('flashFront').innerHTML = `<div><div style="font-size:0.7rem;font-weight:700;letter-spacing:1px;color:${c.cat==='mac'?'var(--primary)':'#f97316'};margin-bottom:10px">${c.cat.toUpperCase()}</div>${f('front')}</div>`;
 document.getElementById('flashBack').innerHTML = f('back');
 document.getElementById('flashCount').textContent = (flashIdx+1)+' / '+flashDeck.length;
 const knew = lang==='fr'?'✓ Je savais':lang==='en'?'✓ I knew it':'✓ Ik wist het';
 const not = lang==='fr'?'✗ À revoir':lang==='en'?'✗ Review again':'✗ Nog herhalen';
 document.getElementById('flashActions').innerHTML = `
 <button style="background:var(--error-bg);color:var(--error)" onclick="nextFlash(false)">${not}</button>
 <button style="background:var(--success-bg);color:var(--success)" onclick="nextFlash(true)">${knew}</button>`;
}
function flipFlash(){
 flashFlipped = !flashFlipped;
 document.getElementById('flashInner').classList.toggle('flipped', flashFlipped);
}
function nextFlash(knew){
 if(!knew){ flashDeck.push(flashDeck[flashIdx]); } // re-queue at the end
 flashIdx++;
 if(flashIdx >= flashDeck.length){
 closeFlash();
 const msg = lang==='fr'?'🎉 Deck terminé, bravo !':lang==='en'?'🎉 Deck finished, well done!':'🎉 Deck klaar, goed gedaan!';
 alert(msg);
 return;
 }
 showFlash();
}

// ── Exam timer ──
const examTimers = {};
function startExamTimer(key){
 const exam = curExams().find(e=>e.key===key);
 if(!exam || examTimers[key]) return;
 let remaining = exam.duration_min * 60;
 const el = document.getElementById('examTimer_'+key);
 const btn = document.getElementById('examTimerBtn_'+key);
 if(btn) btn.style.display = 'none';
 if(el) el.style.display = '';
 const tick = ()=>{
 if(remaining<0){ stopExamTimer(key); gradeExam(key); return; }
 const m = Math.floor(remaining/60), s = remaining%60;
 if(el){
 el.textContent = '⏱ ' + m + ':' + String(s).padStart(2,'0');
 el.classList.toggle('warn', remaining < 300);
 }
 remaining--;
 };
 tick();
 examTimers[key] = setInterval(tick, 1000);
}
function stopExamTimer(key){
 if(examTimers[key]){ clearInterval(examTimers[key]); delete examTimers[key]; }
}

